UPDATE public.questions SET
  stimulus_text = 'The passage begins by describing the challenges of maintaining an old and historic house. It goes on to explain that the author hopes to preserve the house by making use of its historic value. What is the author’s primary purpose in this passage? Taken together, these details imply a broader principle that extends beyond the immediate example, though the author stops short of claiming universal proof. Readers must weigh both the evidence presented and the limits the author acknowledges.',
