  options = '[{"id":"A","text":"explain why the human brain is constantly evolving.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"describe the process of rewiring the brain.","is_correct":true,"explanation":"Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"emphasize the importance of learning and growth.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"suggest that it is never too late to learn something new.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The term "neuroplasticity" is a scientific term that refers to the brain''s ability to change and grow in response to experience. The writer uses this term to explain how the brain rewires itself to create new connections and pathways. The passage states that "A well-known fact about the human brain is that it is constantly evolving. Research indicates that the human brain is in…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: describe the process of rewiring the brain.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
