  options = '[{"id":"A","text":"The narrator is excited about the journey but also anxious about the unknown.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The narrator is feeling nostalgic for the island, which she has visited before.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The narrator is ambivalent about the island, feeling both drawn to and repelled by it.","is_correct":true,"explanation":"Choice C matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The narrator is trying to convince her husband to turn back before they reach the island.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'C',
  explanation = 'The passage uses contrasting language to describe the narrator''s feelings about the island. Words like "familiar" and "alien" as well as "drawn to" and "terrified by" highlight her ambivalence about the journey. The passage states that "The following passage is from a novel set in the early 20th century. The narrator is a young woman who is traveling to a…", which is the textual anchor for eliminating weaker choices. Choice C is correct because it aligns with that evidence: The narrator is ambivalent about the island, feeling both drawn to and repelled by it.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
